/*
 * usb_id_find — binary search in usb_id_table.
 *
 * Searches first for an exact (vid, pid) match.
 * If not found, falls back to the vendor-only entry (pid == 0xFFFF).
 * Fills *vendor_out and *product_out with static string pointers.
 * Returns: 1 exact, 0 vendor-only, -1 not found.
 */
static inline int usb_id_find(uint16_t vid, uint16_t pid,
                               const char **vendor_out,
                               const char **product_out) {
    /* Binary search for exact (vid, pid) match.
     * Table is sorted by (vid asc, pid asc) with 0xFFFF first per vendor. */
    int lo = 0, hi = (int)USB_ID_TABLE_SIZE - 1;
    const char *vendor_fallback = (void*)0;
    const char *product_fallback = (void*)0;

    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        const usb_id_entry_t *e = &usb_id_table[mid];

        if (e->vid < vid || (e->vid == vid && e->pid < pid)) {
            /* Check if this is the vendor-only fallback for our VID */
            if (e->vid == vid && e->pid == 0xFFFF) {
                vendor_fallback  = e->vendor;
                product_fallback = e->product;
            }
            lo = mid + 1;
        } else if (e->vid > vid || (e->vid == vid && e->pid > pid)) {
            /* While scanning downward, also capture vendor-only */
            if (e->vid == vid && e->pid == 0xFFFF) {
                vendor_fallback  = e->vendor;
                product_fallback = e->product;
            }
            hi = mid - 1;
        } else {
            /* Exact match */
            *vendor_out  = e->vendor;
            *product_out = e->product;
            return 1;
        }
    }

    /* No exact match — try vendor-only fallback */
    if (vendor_fallback) {
        /* Linear scan to find the 0xFFFF entry for this VID
         * (binary search may have missed it during the walk) */
        *vendor_out  = vendor_fallback;
        *product_out = product_fallback;
        return 0;
    }

    /* Fallback: scan linearly for vendor-only entry */
    for (int i = 0; i < (int)USB_ID_TABLE_SIZE; i++) {
        if (usb_id_table[i].vid == vid &&
            usb_id_table[i].pid == 0xFFFF) {
            *vendor_out  = usb_id_table[i].vendor;
            *product_out = usb_id_table[i].product;
            return 0;
        }
    }

    *vendor_out  = "Unknown";
    *product_out = "USB Device";
    return -1;
}

#endif /* USB_IDS_GENERATED_H */
